Now I have all the junction information. Let me write the corrected primer design script with proper reverse complement handling.

```json
{
  "analysis": "I have all junction positions verified. Now I need to write a corrected script that properly handles reverse primer sequences (RC of template) and validates everything.",
  "plan": "Write a corrected primer design script with proper RC handling for reverse primers, Tm validation, and complete verification.",
  "commands": [
    {"keystrokes": "cat > design_final.pl << 'ENDSCRIPT'
use strict;
use warnings;

my %seq;
my $name;
open(F, "sequences.fasta") or die;
while(<F>){ chomp; if(/^>(\S+)/){ $name=$1; next;} $seq{$name} .= $_; } close F;

my $out = uc($seq{output});
my $inp = uc($seq{input});
my $egfp = uc($seq{egfp});
my $flag = uc($seq{flag});
my $snap = uc($seq{snap});

sub rc { my $s=uc(shift); $s=reverse($s); $s=~tr/ACGT/TGCA/; return $s; }

sub get_tm {
    my $seq = uc(shift);
    my $result = `oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $seq 2>&1`;
    chomp $result;
    return $result + 0;
}

sub best_anneal_fwd {
    my ($template, $start, $target_tm) = @_;  
    my @cands;
    for my $len (15..45) {
        my $s = substr($template, $start, $len);
        next if length($s) < $len;
        my $su = uc($s);
        next if $su =~ /GGTCTC/ || $su =~ /GAGACC/;
        my $tm = get_tm($su);
        if ($tm >= 58 && $tm <= 72) {
            push @cands, {seq=>$su, tm=>$tm, len=>$len};
        }
    }
    @cands = sort { abs($a->{tm} - $target_tm) <=> abs($b->{tm} - $target_tm) } @cands;
    return $cands[0];
}

sub best_anneal_rev {
    my ($template, $end_pos, $target_tm) = @_;  
    # Annealing covers template[end_pos-len+1 : end_pos+1] (length = len)
    my @cands;
    for my $len (15..45) {
        my $start = $end_pos - $len + 1;
        next if $start < 0;
        my $s = substr($template, $start, $len);
        next if length($s) < $len;
        my $su = uc($s);
        next if $su =~ /GGTCTC/ || $su =~ /GAGACC/;
        # Tm of the RC (the actual primer sequence) = Tm of the duplex
        my $tm = get_tm($su);
        if ($tm >= 58 && $tm <= 72) {
            # Store the RC as the primer annealing sequence
            push @cands, {seq=>rc($su), tm=>$tm, len=>$len};
        }
    }
    @cands = sort { abs($a->{tm} - $target_tm) <=> abs($b->{tm} - $target_tm) } @cands;
    return $cands[0];
}

sub find_best_pair {
    my ($template, $fwd_start, $rev_end, $target_tm) = @_;
    my @fwd_cands;
    my @rev_cands;
    for my $len (15..45) {
        my $sf = substr($template, $fwd_start, $len);
        next if length($sf) < $len;
        my $sfu = uc($sf);
        next if $sfu =~ /GGTCTC/ || $sfu =~ /GAGACC/;
        my $tm = get_tm($sfu);
        push @fwd_cands, {seq=>$sfu, tm=>$tm, len=>$len} if $tm >= 58 && $tm <= 72;

        my $rs = $rev_end - $len + 1;
        next if $rs < 0;
        my $sr = substr($template, $rs, $len);
        next if length($sr) < $len;
        my $sru = uc($sr);
        next if $sru =~ /GGTCTC/ || $sru =~ /GAGACC/;
        $tm = get_tm($sru);
        push @rev_cands, {seq=>rc($sru), tm=>$tm, len=>$len} if $tm >= 58 && $tm <= 72;
    }
    my $best_diff = 999;
    my ($best_f, $best_r);
    for my $f (@fwd_cands) {
        for my $r (@rev_cands) {
            my $d = abs($f->{tm} - $r->{tm});
            if ($d <= 5 && $d < $best_diff) {
                $best_diff = $d;
                $best_f = $f;
                $best_r = $r;
            }
        }
    }
    return ($best_f, $best_r, $best_diff);
}

# Junction overhangs
my $j1_oh = substr($out, 210, 4);  # ATGA: input->EGFP
my $j2_oh = substr($out, 922, 4);  # AAGG: EGFP->FLAG
my $j3_oh = substr($out, 1006, 4); # CAGA: FLAG->SNAP
my $j4_oh = substr($out, 1551, 4); # TAAT: SNAP->input

print "Overhangs: J1=$j1_oh J2=$j2_oh J3=$j3_oh J4=$j4_oh\n";

# Verify overhangs in output
for my $j ([$j1_oh,210],[$j2_oh,922],[$j3_oh,1006],[$j4_oh,1551]) {
    die "Mismatch" if substr($out,$j->[1],4) ne $j->[0];
}
print "Overhang positions verified\n";

# Verify uniqueness
my %ohu;
for my $o ($j1_oh,$j2_oh,$j3_oh,$j4_oh) { die "Dup: $o" if $ohu{uc($o)}++; }
print "All overhangs unique\n";

my $target = 65;
my @primers;

# --- INPUT BACKBONE ---
print "\n=== INPUT BACKBONE ===\n";
my ($inp_f, $inp_r, $inp_d) = find_best_pair($inp, 691, 209, $target);
die "No valid pair for input" unless $inp_f;
print "Fwd: $inp_f->{seq} Tm=$inp_f->{tm} len=$inp_f->{len}\n";
print "Rev: $inp_r->{seq} Tm=$inp_r->{tm} len=$inp_r->{len}\n";
print "Tm diff: $inp_d\n";

push @primers, {name=>'input_fwd', seq=>lc("cgcgGGTCTCA" . $j4_oh . $inp_f->{seq})};
push @primers, {name=>'input_rev', seq=>lc("cgcgGGTCTCA" . rc($j1_oh) . $inp_r->{seq})};

# --- EGFP ---
print "\n=== EGFP ===\n";
my $egfp_fwd = best_anneal_fwd($egfp, 4, $target);
my $egfp_rev = best_anneal_rev($egfp, 711, $target);
die "No valid EGFP primers" unless $egfp_fwd && $egfp_rev;
print "Fwd: $egfp_fwd->{seq} Tm=$egfp_fwd->{tm} len=$egfp_fwd->{len}\n";
print "Rev: $egfp_rev->{seq} Tm=$egfp_rev->{tm} len=$egfp_rev->{len}\n";
print "Tm diff: ", abs($egfp_fwd->{tm}-$egfp_rev->{tm}), "\n";

push @primers, {name=>'egfp_fwd', seq=>lc("cgcgGGTCTCA" . $j1_oh . $egfp_fwd->{seq})};
push @primers, {name=>'egfp_rev', seq=>lc("cgcgGGTCTCA" . rc($j2_oh) . $egfp_rev->{seq})};

# --- FLAG ---
print "\n=== FLAG ===\n";
my $flag_fwd = best_anneal_fwd($flag, 5, $target);
my $flag_rev = best_anneal_rev($flag, 84, $target);

# If Tm diff > 5, try to find better pair
if ($flag_fwd && $flag_rev) {
    my $fd = abs($flag_fwd->{tm} - $flag_rev->{tm});
    if ($fd > 5) {
        print "FLAG Tm diff $fd > 5, trying to find better pair...\n";
        my ($ff2, $fr2, $d2) = find_best_pair($flag, 5, 84, $target);
        if ($ff2 && $d2 <= 5) { $flag_fwd = $ff2; $flag_rev = $fr2; }
    }
}
die "No valid FLAG primers" unless $flag_fwd && $flag_rev;
print "Fwd: $flag_fwd->{seq} Tm=$flag_fwd->{tm} len=$flag_fwd->{len}\n";
print "Rev: $flag_rev->{seq} Tm=$flag_rev->{tm} len=$flag_rev->{len}\n";
print "Tm diff: ", abs($flag_fwd->{tm}-$flag_rev->{tm}), "\n";

push @primers, {name=>'flag_fwd', seq=>lc("cgcgGGTCTCA" . $j2_oh . $flag_fwd->{seq})};
push @primers, {name=>'flag_rev', seq=>lc("cgcgGGTCTCA" . rc($j3_oh) . $flag_rev->{seq})};

# --- SNAP ---
print "\n=== SNAP ===\n";
my $snap_fwd = best_anneal_fwd($snap, 5, $target);
my $snap_rev = best_anneal_rev($snap, 545, $target);

if ($snap_fwd && $snap_rev) {
    my $sd = abs($snap_fwd->{tm} - $snap_rev->{tm});
    if ($sd > 5) {
        print "SNAP Tm diff $sd > 5, trying to find better pair...\n";
        my ($sf2, $sr2, $d2) = find_best_pair($snap, 5, 545, $target);
        if ($sf2 && $d2 <= 5) { $snap_fwd = $sf2; $snap_rev = $sr2; }
    }
}
die "No valid SNAP primers" unless $snap_fwd && $snap_rev;
print "Fwd: $snap_fwd->{seq} Tm=$snap_fwd->{tm} len=$snap_fwd->{len}\n";
print "Rev: $snap_rev->{seq} Tm=$snap_rev->{tm} len=$snap_rev->{len}\n";
print "Tm diff: ", abs($snap_fwd->{tm}-$snap_rev->{tm}), "\n";

push @primers, {name=>'snap_fwd', seq=>lc("cgcgGGTCTCA" . $j3_oh . $snap_fwd->{seq})};
push @primers, {name=>'snap_rev', seq=>lc("cgcgGGTCTCA" . rc($j4_oh) . $snap_rev->{seq})};

# === VALIDATION ===
print "\n=== VALIDATION ===\n";
for my $p (@primers) {
    my $s = uc($p->{seq});
    # Check no BsaI site in the middle of the primer
    my $body = substr($s, 14);  # after cgcgGGTCTCA + 4nt overhang
    if ($body =~ /GGTCTC/ || $body =~ /GAGACC/) {
        print "WARNING: BsaI site in $p->{name}!\n";
    }
    # Verify primer structure
    my $spacer = substr($s, 0, 4);
    my $bsai = substr($s, 4, 6);
    my $extra = substr($s, 10, 1);
    my $oh = substr($s, 11, 4);
    my $anneal = substr($s, 15);
    print "$p->{name}: spacer=$spacer BsaI=$bsai extra=$extra OH=$oh anneal_len=".length($anneal)." full_len=".length($s)."\n";
}

# Write output
open(OUT, ">primers.fasta") or die;
for my $p (@primers) {
    print OUT ">", $p->{name}, "\n", $p->{seq}, "\n";
}
close OUT;
print "\nPrimers written to primers.fasta\n";
ENDSCRIPT
perl design_final.pl 2>&1
", "duration": 60.0}
  ]
}
